# ====================== 輔助函式 ======================

def get_key_info(number: int, ke: str = "初刻", category: str = "時辰") -> Any:
    if number not in SHAOZI_64_KEYS:
        return f"第{number}數 資料尚未結構化"
    key_data = SHAOZI_64_KEYS[number]
    if category == "特殊":
        return key_data.get("特殊", [])
    if category in key_data:
        sub = key_data[category]
        if isinstance(sub, dict):
            return sub.get(ke, "無此項目資料")
        return sub
    return "查無此類別資料"


def get_special_notes(number: int) -> List[str]:
    if number not in SHAOZI_64_KEYS:
        return []
    return SHAOZI_64_KEYS[number].get("特殊", [])


def get_key_name(number: int) -> str:
    if number not in SHAOZI_64_KEYS:
        return f"第{number}數"
    return SHAOZI_64_KEYS[number].get("名稱", f"第{number}數")


def get_detailed_key(number: int) -> Dict[str, Any]:
    if number not in SHAOZI_64_KEYS:
        return {"error": f"第{number}數 資料尚未結構化"}
    return SHAOZI_64_KEYS[number]


def list_available_keys() -> List[int]:
    return sorted(SHAOZI_64_KEYS.keys())


